patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..4395e40bbbc5 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1706,6 +1706,7 @@ static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
   return Clone;
 }

+
 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                 bool FoldWithMultiUse) {
   // Don't modify shared select instructions unless set FoldWithMultiUse
@@ -1734,6 +1735,30 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
     }
   }

+  // Special case: select based on fcmp ord TV, 0.0 with false value 0.0,
+  // and the operation is an ordered fcmp. We can bypass the select.
+  if (auto *FCI = dyn_cast<FCmpInst>(&Op)) {
+    if (auto *CondCmp = dyn_cast<FCmpInst>(SI->getCondition())) {
+      if (CondCmp->getPredicate() == FCmpInst::FCMP_ORD &&
+          CondCmp->getOperand(0) == TV &&
+          match(CondCmp->getOperand(1), m_Zero()) &&
+          match(FV, m_AnyZeroFP()) &&
+          FCI->isOrdered()) {
+        // Create new fcmp with same predicate, comparing TV to Op's other operand
+        Value *OtherOp = (FCI->getOperand(0) == SI) ? FCI->getOperand(1) : FCI->getOperand(0);
+        if (OtherOp == SI) {
+          // Both operands are the select? Shouldn't happen for ordered fcmp.
+          return nullptr;
+        }
+        // Ensure we're comparing against a constant for safety
+        if (isa<Constant>(OtherOp)) {
+          return FCmpInst::Create(FCI->getOpcode(), FCI->getPredicate(),
+                                  TV, OtherOp, "", SI);
+        }
+      }
+    }
+  }
+
   // Make sure that one of the select arms folds successfully.
   Value *NewTV = simplifyOperationIntoSelectOperand(Op, SI, /*IsTrueArm=*/true);
   Value *NewFV =
@@ -1749,6 +1774,7 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
 }

+
 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
                                          Value *InValue, BasicBlock *InBB,
                                          const DataLayout &DL,
